import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public void processUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Validate and sanitize user input to prevent XSS
        if(userInput != null) {
            userInput = StringEscapeUtils.escapeHtml4(userInput);
        } else {
            userInput = "Guest"; // Default value if input is empty
        }

        String output = "Hello, " + userInput + "!";

        // Properly handling user input with validation and encoding
        response.getWriter().println(output);
    }

}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
